settings.custom_liquid:
{% if product.available %}
<div style="text-align: center;">
  <div class="instock-pulse">
    <span class="icon--pulsing"></span>
    <span id="low-stock-message" style="color: #000;">In stock, ready to ship </span>
  </div>



  <style>
    .instock-pulse {
      display: flex;
      flex-wrap: nowrap;
      align-items: center;
      justify-content: center;
    }

    .icon--pulsing {
      position: relative;
      width: 20px;
      height: 20px;
      margin-right: 10px;
    }

    .icon--pulsing:after,
    .icon--pulsing:before {
      background: #55C53A;
      width: 10px;
      height: 10px;
      border-radius: 10px;
      position: absolute;
      left: 0;
      top: 0;
      content: "";
      margin: 5px;
    }

    @keyframes inventory-pulse {
      0% {
        opacity: 0.5;
      }
      to {
        transform: scale(2.5);
        opacity: 0;
      }
    }

    .icon--pulsing:before {
      animation: inventory-pulse 2s linear infinite;
    }

    /* Media Query for Font Size on Mobile */
    @media (max-width: 768px) {
      #low-stock-message {
        font-size: 15px;
      }
    }
  </style>
</div>
{% endif %}
